7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This is a very basic asynchronous FIFO. The clocks can be fully asynchronous
11	-- (unrelated). It  has optional level- and almost-full/empty ports.
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_fifo_async.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Libraries
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_logic.all;
29	    use work.olo_base_pkg_string.all;
30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity
33	---------------------------------------------------------------------------------------------------
34	entity olo_base_fifo_async is
35	    generic (
36	        Width_g         : positive;
37	        Depth_g         : positive; -- must be power of two
38	        AlmFullOn_g     : boolean               := false;
39	        AlmFullLevel_g  : natural               := 0;
40	        AlmEmptyOn_g    : boolean               := false;
41	        AlmEmptyLevel_g : natural               := 0;
42	        RamStyle_g      : string                := "auto";
43	        RamBehavior_g   : string                := "RBW";
44	        ReadyRstState_g : std_logic             := '1';
45	        Optimization_g  : string                := "SPEED"; -- SPEED or LATENCY
46	        SyncStages_g    : positive range 2 to 4 := 2
47	    );
48	    port (
49	        -- Input interface
50	        In_Clk          : in    std_logic;
51	        In_Rst          : in    std_logic;
52	        In_RstOut       : out   std_logic;
53	        In_Data         : in    std_logic_vector(Width_g-1 downto 0);
54	        In_Valid        : in    std_logic := '1';
55	        In_Ready        : out   std_logic;
56	        -- Input Status
57	        In_Full         : out   std_logic;
58	        In_Empty        : out   std_logic;
59	        In_AlmFull      : out   std_logic;
60	        In_AlmEmpty     : out   std_logic;
61	        In_Level        : out   std_logic_vector(log2ceil(Depth_g+1)-1 downto 0);
62	        -- Output Interface
63	        Out_Clk         : in    std_logic;
64	        Out_Rst         : in    std_logic;
65	        Out_RstOut      : out   std_logic;
66	        Out_Data        : out   std_logic_vector(Width_g-1 downto 0);
67	        Out_Valid       : out   std_logic;
68	        Out_Ready       : in    std_logic := '1';
69	        -- Output Status
70	        Out_Full        : out   std_logic;
71	        Out_Empty       : out   std_logic;
72	        Out_AlmFull     : out   std_logic;
73	        Out_AlmEmpty    : out   std_logic;
74	        Out_Level       : out   std_logic_vector(log2ceil(Depth_g+1)-1 downto 0)
75	    );
76	end entity;
77	
78	---------------------------------------------------------------------------------------------------
79	-- Architecture
80	---------------------------------------------------------------------------------------------------
81	architecture rtl of olo_base_fifo_async is
82	
83	    constant EntityName_c   : string   := "olo_base_fifo_async";
84	    constant AddrWidth_c    : positive := log2ceil(Depth_g)+1;
85	    constant RamAddrWidth_c : positive := log2ceil(Depth_g);
86	
87	    type TwoProcessIn_r is record
88	        WrAddr     : unsigned(AddrWidth_c-1 downto 0); -- One additional bit for full/empty detection
89	        WrAddrGray : std_logic_vector(AddrWidth_c-1 downto 0);
90	        RdAddr     : unsigned(AddrWidth_c-1 downto 0);
91	        WrAddrReg  : unsigned(AddrWidth_c-1 downto 0);
92	        RamWr      : std_logic;
93	        DataReg    : std_logic_vector(Width_g-1 downto 0);
94	    end record;
95	
96	    type TwoProcessOut_r is record
97	        RdAddr     : unsigned(AddrWidth_c-1 downto 0); -- One additional bit for full/empty detection
98	        RdAddrGray : std_logic_vector(AddrWidth_c-1 downto 0);
99	        WrAddr     : unsigned(AddrWidth_c-1 downto 0);
100	        OutLevel   : unsigned(AddrWidth_c-1 downto 0);
101	    end record;
102	
103	    signal ri, ri_next : TwoProcessIn_r := (WrAddr          => (others => '0'),
104	                                             WrAddrGray     => (others => '0'),
105	                                             RdAddr         => (others => '0'),
106	                                             WrAddrReg      => (others => '0'),
107	                                             RamWr          => '0',
108	                                            DataReg         => (others => '0'));
109	
110	    signal ro, ro_next : TwoProcessOut_r := (RdAddr          => (others => '0'),
111	                                              RdAddrGray     => (others => '0'),
112	                                              WrAddr         => (others => '0'),
113	                                              OutLevel       => (others => '0'));
114	
115	    signal RstInInt     : std_logic;
116	    signal RstOutInt    : std_logic;
117	    signal RamRdAddr    : std_logic_vector(RamAddrWidth_c-1 downto 0);
118	    signal RamWrAddr    : std_logic_vector(RamAddrWidth_c-1 downto 0);
119	    signal RamWr        : std_logic;
120	    signal RamWrData    : std_logic_vector(Width_g-1 downto 0);
121	    signal WrAddrGray   : std_logic_vector(AddrWidth_c-1 downto 0);
122	    signal RdAddrGray   : std_logic_vector(AddrWidth_c-1 downto 0);
123	    signal WrAddrGrayIn : std_logic_vector(AddrWidth_c-1 downto 0);
124	    signal RdAddrGrayIn : std_logic_vector(AddrWidth_c-1 downto 0);
125	
126	begin
127	
128	    assert log2(Depth_g) = log2ceil(Depth_g)
129	        report errorMessage(EntityName_c, "only power of two Depth_g is allowed")
130	        severity error;
131	
132	    p_comb : process (all) is
133	        variable vi        : TwoProcessIn_r;
134	        variable vo        : TwoProcessOut_r;
135	        variable InLevel_v : unsigned(log2ceil(Depth_g) downto 0);
136	    begin
137	        -- *** hold variables stable ***
138	        vi := ri;
139	        vo := ro;
140	
141	        -- *** Write Side ***
142	        -- Defaults
143	        In_Ready    <= '0';
144	        In_Full     <= '0';
145	        In_Empty    <= '0';
146	        In_AlmFull  <= '0';
147	        In_AlmEmpty <= '0';
148	        vi.RamWr    := '0';
149	
150	        -- Level Detection
151	        InLevel_v := ri.WrAddr - ri.RdAddr;
152	        In_Level  <= std_logic_vector(InLevel_v);
153	
154	        -- Full
155	        -- if InLevel_v = Depth_g then --> Below if-condition implements this in a more timing optimal way
156	        -- .. by avoiding relying on the carry chain for InLevel_v. Equivalence is given becasue FIFO
157	        -- .. depth is power of two.
158	        if (ri.WrAddr(ri.WrAddr'left) /= ri.RdAddr(ri.RdAddr'left)) and
159	           (ri.WrAddr(ri.WrAddr'left-1 downto 0) = ri.RdAddr(ri.RdAddr'left-1 downto 0)) then
160	            In_Full <= '1';
161	        else
162	            In_Ready <= '1';
163	            -- Execute Write
164	            if In_Valid = '1' then
165	                vi.WrAddr := ri.WrAddr + 1;
166	                vi.RamWr  := '1';
167	            end if;
168	        end if;
169	        -- Artificially keep InRdy low during reset if required
170	        if (ReadyRstState_g = '0') and (RstInInt = '1') then
171	            In_Ready <= '0';
172	        end if;
173	
174	        -- Status Detection
175	        if InLevel_v = 0 then
176	            In_Empty <= '1';
177	        end if;
178	        if InLevel_v >= AlmFullLevel_g and AlmFullOn_g then
179	            In_AlmFull <= '1';
180	        end if;
181	        if InLevel_v <= AlmEmptyLevel_g and AlmEmptyOn_g then
182	            In_AlmEmpty <= '1';
183	        end if;
184	
185	        -- Pipeline registers for speed optimization
186	        vi.WrAddrReg := ri.WrAddr;
187	        vi.DataReg   := In_Data;
188	
189	        -- *** Read Side ***
190	        -- Defaults
191	        Out_Valid    <= '0';
192	        Out_Full     <= '0';
193	        Out_Empty    <= '0';
194	        Out_AlmFull  <= '0';
195	        Out_AlmEmpty <= '0';
196	
197	        -- Level Detection
198	        if ro.WrAddr = ro.RdAddr then
199	            vo.OutLevel := (others => '0');
200	        else
201	            vo.OutLevel := ro.WrAddr - ro.RdAddr;
202	            if (Out_Ready = '1') and (ro.OutLevel /= 0) then
203	                vo.OutLevel := vo.OutLevel - 1;
204	            end if;
205	        end if;
206	        Out_Level <= std_logic_vector(ro.OutLevel);
207	
208	        -- Empty
209	        if ro.OutLevel = 0 then
210	            Out_Empty <= '1';
211	        else
212	            Out_Valid <= '1';
213	            -- Execute read
214	            if Out_Ready = '1' then
215	                vo.RdAddr := ro.RdAddr + 1;
216	            end if;
217	        end if;
218	        RamRdAddr <= std_logic_vector(vo.RdAddr(log2ceil(Depth_g) - 1 downto 0));
219	
220	        -- Status Detection
221	        if ro.OutLevel = Depth_g then
222	            Out_Full <= '1';
223	        end if;
224	        if ro.OutLevel >= AlmFullLevel_g and AlmFullOn_g then
225	            Out_AlmFull <= '1';
226	        end if;
227	        if ro.OutLevel <= AlmEmptyLevel_g and AlmEmptyOn_g then
228	            Out_AlmEmpty <= '1';
229	        end if;
230	
231	        -- *** Address Clock domain crossings ***
232	        -- Bin->Gray is simple, can be done without additional FF
233	        vi.WrAddrGray := binaryToGray(std_logic_vector(vi.WrAddr));
234	        vo.RdAddrGray := binaryToGray(std_logic_vector(vo.RdAddr));
235	
236	        -- Gray->Bin involves some logic, needs additional FF
237	        vi.RdAddr := unsigned(grayToBinary(RdAddrGray));
238	        vo.WrAddr := unsigned(grayToBinary(WrAddrGray));
239	
240	        -- *** Assign signal ***
241	        ri_next <= vi;
242	        ro_next <= vo;
243	
244	    end process;
245	
246	    p_seq_in : process (In_Clk) is
247	    begin
248	        if rising_edge(In_Clk) then
249	            ri <= ri_next;
250	            if RstInInt = '1' then
251	                ri.WrAddr     <= (others => '0');
252	                ri.WrAddrGray <= (others => '0');
253	                ri.RdAddr     <= (others => '0');
254	                ri.RamWr      <= '0';
255	            end if;
256	        end if;
257	    end process;
258	
259	    p_seq_out : process (Out_Clk) is
260	    begin
261	        if rising_edge(Out_Clk) then
262	            ro <= ro_next;
263	            if RstOutInt = '1' then
264	                ro.RdAddr     <= (others => '0');
265	                ro.RdAddrGray <= (others => '0');
266	                ro.WrAddr     <= (others => '0');
267	                ro.OutLevel   <= (others => '0');
268	            end if;
269	        end if;
270	    end process;
271	
272	    -- Optional pipeline stage for speed optimization
273	    RamWrAddr <= std_logic_vector(ri.WrAddr(log2ceil(Depth_g) - 1 downto 0)) when compareNoCase(Optimization_g, "LATENCY") else
274	                 std_logic_vector(ri.WrAddrReg(log2ceil(Depth_g) - 1 downto 0));
275	    RamWr     <= ri_next.RamWr when compareNoCase(Optimization_g, "LATENCY") else ri.RamWr;
276	    RamWrData <= In_Data when compareNoCase(Optimization_g, "LATENCY") else ri.DataReg;
277	
278	    i_ram : entity work.olo_base_ram_sdp
279	        generic map (
280	            Depth_g         => Depth_g,
281	            Width_g         => Width_g,
282	            RamStyle_g      => RamStyle_g,
283	            IsAsync_g       => true,
284	            RamBehavior_g   => RamBehavior_g
285	        )
286	        port map (
287	            Clk         => In_Clk,
288	            Wr_Addr     => RamWrAddr,
289	            Wr_Ena      => RamWr,
290	            Wr_Data     => RamWrData,
291	            Rd_Clk      => Out_Clk,
292	            Rd_Addr     => RamRdAddr,
293	            Rd_Data     => Out_Data
294	        );
295	
296	    -- Wr -> Rd Sync
297	    WrAddrGrayIn <= ri_next.WrAddrGray when compareNoCase(Optimization_g, "LATENCY") else ri.WrAddrGray; -- optional register stage
298	
299	    i_cc_wr_rd : entity work.olo_base_cc_bits
300	        generic map (
301	            Width_g      => AddrWidth_c,
302	            SyncStages_g => SyncStages_g
303	        )
304	        port map (
305	            In_Clk   => In_Clk,
306	            In_Rst   => RstInInt,
307	            In_Data  => WrAddrGrayIn,
308	            Out_Clk  => Out_Clk,
309	            Out_Rst  => RstOutInt,
310	            Out_Data => WrAddrGray
311	        );
312	
313	    -- Rd -> Wr Sync
314	    RdAddrGrayIn <= ro_next.RdAddrGray when compareNoCase(Optimization_g, "LATENCY") else ro.RdAddrGray; -- optional register stage
315	
316	    i_cc_rd_wr : entity work.olo_base_cc_bits
317	        generic map (
318	            Width_g      => AddrWidth_c,
319	            SyncStages_g => SyncStages_g
320	        )
321	        port map (
322	            In_Clk   => Out_Clk,
323	            In_Rst   => RstOutInt,
324	            In_Data  => RdAddrGrayIn, -- use unregistered signal because CC contains register
325	            Out_Clk  => In_Clk,
326	            Out_Rst  => RstInInt,
327	            Out_Data => RdAddrGray
328	        );
329	
330	    -- Reset CC
331	    i_rst_cc : entity work.olo_base_cc_reset
332	        port map (
333	            A_Clk       => In_Clk,
334	            A_RstIn     => In_Rst,
335	            A_RstOut    => RstInInt,
336	            B_Clk       => Out_Clk,
337	            B_RstIn     => Out_Rst,
338	            B_RstOut    => RstOutInt
339	        );
340	
341	    Out_RstOut <= RstOutInt;
342	    In_RstOut  <= RstInInt;
343	
344	end architecture;
345

