4	-- Authors: Oliver Bruendler
5	---------------------------------------------------------------------------------------------------
6	
7	---------------------------------------------------------------------------------------------------
8	-- Libraries
9	---------------------------------------------------------------------------------------------------
10	library ieee;
11	    use ieee.std_logic_1164.all;
12	    use ieee.numeric_std.all;
13	
14	library vunit_lib;
15	    context vunit_lib.vunit_context;
16	
17	library olo;
18	    use olo.olo_base_pkg_math.all;
19	    use olo.olo_base_pkg_logic.all;
20	
21	---------------------------------------------------------------------------------------------------
22	-- Entity
23	---------------------------------------------------------------------------------------------------
24	-- vunit: run_all_in_same_sim
25	entity olo_base_fifo_async_tb is
26	    generic (
27	        runner_cfg      : string;
28	        AlmFullOn_g     : boolean              := true;
29	        AlmEmptyOn_g    : boolean              := true;
30	        Depth_g         : natural              := 32;
31	        RamBehavior_g   : string               := "RBW";
32	        ReadyRstState_g : integer range 0 to 1 := 1;
33	        Optimization_g  : string               := "LATENCY";
34	        SyncStages_g    : integer range 2 to 4 := 2
35	    );
36	end entity;
37	
38	architecture sim of olo_base_fifo_async_tb is
39	
40	    -----------------------------------------------------------------------------------------------
41	    -- Constants
42	    -----------------------------------------------------------------------------------------------
43	    constant DataWidth_c     : integer := 16;
44	    constant AlmFullLevel_c  : natural := Depth_g - 3;
45	    constant AlmEmptyLevel_c : natural := 5;
46	
47	    -----------------------------------------------------------------------------------------------
48	    -- TB Defnitions
49	    -----------------------------------------------------------------------------------------------
50	    constant ClockInFrequency_c  : real := 100.0e6;
51	    constant ClockInPeriod_c     : time := (1 sec) / ClockInFrequency_c;
52	    constant ClockOutFrequency_c : real := 83.333e6;
53	    constant ClockOutPeriod_c    : time := (1 sec) / ClockOutFrequency_c;
54	
55	    -----------------------------------------------------------------------------------------------
56	    -- Interface Signals
57	    -----------------------------------------------------------------------------------------------
58	    signal In_Clk       : std_logic                                        := '0';
59	    signal In_Rst       : std_logic                                        := '1';
60	    signal Out_Clk      : std_logic                                        := '0';
61	    signal Out_Rst      : std_logic                                        := '1';
62	    signal In_Data      : std_logic_vector(DataWidth_c-1 downto 0)         := (others => '0');
63	    signal In_Valid     : std_logic                                        := '0';
64	    signal In_Ready     : std_logic                                        := '0';
65	    signal Out_Data     : std_logic_vector(DataWidth_c-1 downto 0)         := (others => '0');
66	    signal Out_Valid    : std_logic                                        := '0';
67	    signal Out_Ready    : std_logic                                        := '0';
68	    signal In_Full      : std_logic                                        := '0';
69	    signal Out_Full     : std_logic                                        := '0';
70	    signal In_Empty     : std_logic                                        := '0';
71	    signal Out_Empty    : std_logic                                        := '0';
72	    signal In_AlmFull   : std_logic                                        := '0';
73	    signal Out_AlmFull  : std_logic                                        := '0';
74	    signal In_AlmEmpty  : std_logic                                        := '0';
75	    signal Out_AlmEmpty : std_logic                                        := '0';
76	    signal In_Level     : std_logic_vector(log2ceil(Depth_g+1)-1 downto 0) := (others => '0');
77	    signal Out_Level    : std_logic_vector(log2ceil(Depth_g+1)-1 downto 0) := (others => '0');
78	
79	begin
80	
81	    -----------------------------------------------------------------------------------------------
82	    -- DUT
83	    -----------------------------------------------------------------------------------------------
84	    i_dut : entity olo.olo_base_fifo_async
85	        generic map (
86	            Width_g         => DataWidth_c,
87	            Depth_g         => Depth_g,
88	            AlmFullOn_g     => AlmFullOn_g,
89	            AlmFullLevel_g  => AlmFullLevel_c,
90	            AlmEmptyOn_g    => AlmEmptyOn_g,
91	            AlmEmptyLevel_g => AlmEmptyLevel_c,
92	            RamBehavior_g   => RamBehavior_g,
93	            ReadyRstState_g => toStdl(ReadyRstState_g),
94	            Optimization_g  => Optimization_g,
95	            SyncStages_g    => SyncStages_g
96	        )
97	        port map (
98	            -- Control Ports
99	            In_Clk          => In_Clk,
100	            In_Rst          => In_Rst,
101	            Out_Clk         => Out_Clk,
102	            Out_Rst         => Out_Rst,
103	            -- Input Data
104	            In_Data         => In_Data,
105	            In_Valid        => In_Valid,
106	            In_Ready        => In_Ready,
107	            -- Output Data
108	            Out_Data        => Out_Data,
109	            Out_Valid       => Out_Valid,
110	            Out_Ready       => Out_Ready,
111	            -- Input Status
112	            In_Full         => In_Full,
113	            In_Empty        => In_Empty,
114	            In_AlmFull      => In_AlmFull,
115	            In_AlmEmpty     => In_AlmEmpty,
116	            In_Level        => In_Level,
117	            -- Output Status
118	            Out_Full        => Out_Full,
119	            Out_Empty       => Out_Empty,
120	            Out_AlmFull     => Out_AlmFull,
121	            Out_AlmEmpty    => Out_AlmEmpty,
122	            Out_Level       => Out_Level
123	        );
124	
125	    -----------------------------------------------------------------------------------------------
126	    -- Clock
127	    -----------------------------------------------------------------------------------------------
128	    In_Clk  <= not In_Clk after 0.5 * ClockInPeriod_c;
129	    Out_Clk <= not Out_Clk after 0.5 * ClockOutPeriod_c;
130	
131	    -----------------------------------------------------------------------------------------------
132	    -- TB Control
133	    -----------------------------------------------------------------------------------------------
134	    test_runner_watchdog(runner, 10 ms);
135	
136	    p_control : process is
137	    begin
138	        test_runner_setup(runner, runner_cfg);
139	
140	        while test_suite loop
141	
142	            -- reset
143	            In_Rst  <= '1';
144	            Out_Rst <= '1';
145	            -- check if ready state during reset is correct
146	            wait for 20 ns;                     -- reset must be transferred to other clock domain
147	            wait until rising_edge(In_Clk);
148	            check_equal(In_Ready, toStdl(ReadyRstState_g), "In_Ready reset state not according to generic");
149	            wait for 1 us;
150	
151	            -- Remove reset
152	            wait until rising_edge(In_Clk);
153	            In_Rst  <= '0';
154	            wait until rising_edge(Out_Clk);
155	            Out_Rst <= '0';
156	            wait for 100 ns;
157	
158	            -- Check Reset State
159	            wait until rising_edge(In_Clk);
160	            check_equal(In_Ready, '1', "In_Ready after reset state not '1'");
161	            check_equal(In_Full, '0', "In_Full reset state not '0'");
162	            check_equal(In_Empty, '1', "In_Empty reset state not '1'");
163	            check_equal(In_Level, 0, "In_Level reset state not 0");
164	            if AlmFullOn_g then
165	                check_equal(In_AlmFull, '0', "In_AlmFull reset state not '0'");
166	            end if;
167	            if AlmEmptyOn_g then
168	                check_equal(In_AlmEmpty, '1', "In_AlmEmpty reset state not '1'");
169	            end if;
170	
171	            wait until rising_edge(Out_Clk);
172	            check_equal(Out_Valid, '0', "Out_Valid reset state not '0'");
173	            check_equal(Out_Full, '0', "Out_Full reset state not '0'");
174	            check_equal(Out_Empty, '1', "Out_Empty reset state not '1'");
175	            check_equal(Out_Level, 0, "Out_Level reset state not 0");
176	            if AlmFullOn_g then
177	                check_equal(Out_AlmFull, '0', "Out_AlmFull reset state not '0'");
178	            end if;
179	            if AlmEmptyOn_g then
180	                check_equal(Out_AlmEmpty, '1', "Out_AlmEmpty reset state not '1'");
181	            end if;
182	
183	            if run("TwoWordsWriteAndRead") then
184	
185	                -- Write 1
186	                wait until falling_edge(In_Clk);
187	                In_Data  <= x"0001";
188	                In_Valid <= '1';
189	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
190	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
191	                check_equal(In_Empty, '1', "In_Empty not high");
192	                check_equal(In_Level, 0, "In_Level not 0");
193	
194	                -- Write 2
195	                wait until falling_edge(In_Clk);
196	                In_Data <= x"0002";
197	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
198	                check_equal(In_Empty, '0', "Empty not low");
199	                check_equal(In_Level, 1, "In_Level not 1");
200	
201	                -- Pause 1
202	                wait until falling_edge(In_Clk);
203	                In_Data  <= x"0003";
204	                In_Valid <= '0';
205	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
206	                check_equal(In_Empty, '0', "Empty not low");
207	                check_equal(In_Level, 2, "In_Level not 2");
208	
209	                -- Pause 2
210	                for i in 0 to 5 loop
211	                    wait until falling_edge(In_Clk);
212	                    wait until falling_edge(Out_Clk);
213	                end loop;
214	
215	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
216	                check_equal(Out_Valid, '1', "Out_Valid not high");
217	                check_equal(Out_Data, 16#0001#, "Illegal Out_Data 1");
218	                check_equal(In_Empty, '0', "In_Empty not low");
219	                check_equal(In_Full, '0', "In_Full not low");
220	                check_equal(Out_Empty, '0', "In_Empty not low");
221	                check_equal(Out_Full, '0', "In_Full not low");
222	                check_equal(In_Level, 2, "In_Level not 2");
223	                check_equal(Out_Level, 2, "Out_Level not 2");
224	
225	                -- Read ack 1
226	                wait until falling_edge(Out_Clk);
227	                Out_Ready <= '1';
228	                check_equal(Out_Valid, '1', "Out_Valid not high");
229	                check_equal(Out_Data, 16#0001#, "Illegal Out_Data 1");
230	                check_equal(Out_Empty, '0', "Empty not low");
231	                check_equal(Out_Level, 2, "Out_Level not 2");
232	
233	                -- Read ack 2
234	                wait until falling_edge(Out_Clk);
235	                check_equal(Out_Valid, '1', "Out_Valid not high");
236	                check_equal(Out_Data, 16#0002#, "Illegal Out_Data 2");
237	                check_equal(Out_Empty, '0', "Empty not low");
238	                check_equal(Out_Level, 1, "Out_Level not 1");
239	
240	                -- empty 1
241	                wait until falling_edge(Out_Clk);
242	                Out_Ready <= '0';
243	                check_equal(Out_Valid, '0', "Out_Valid not high");
244	                check_equal(Out_Empty, '1', "Empty not high");
245	                check_equal(Out_Level, 0, "Out_Level not 0");
246	
247	                -- empty 2
248	                for i in 0 to 4 loop
249	                    wait until falling_edge(Out_Clk);
250	                    wait until falling_edge(In_Clk);
251	                end loop;
252	
253	                check_equal(In_Ready, '1', "In_Ready went low unexpectedly");
254	                check_equal(Out_Valid, '0', "Out_Valid not high");
255	                check_equal(In_Empty, '1', "In_Empty not high");
256	                check_equal(Out_Empty, '1', "Out_Empty not high");
257	                check_equal(In_Full, '0', "In_Full not low");
258	                check_equal(Out_Full, '0', "Out_Full not low");
259	                check_equal(In_Level, 0, "In_Level not 0");
260	                check_equal(Out_Level, 0, "Out_Level not 0");
261	
262	            elsif run("WriteFullFifo") then
263	                wait until falling_edge(In_Clk);
264	
265	                -- Fill FIFO
266	                for i in 0 to Depth_g - 1 loop
267	                    In_Valid <= '1';
268	                    In_Data  <= std_logic_vector(to_unsigned(i, In_Data'length));
269	                    wait until falling_edge(In_Clk);
270	                end loop;
271	
272	                In_Valid <= '0';
273	                wait for 1 us;
274	                check_equal(In_Full, '1', "In_Full not asserted");
275	                check_equal(Out_Full, '1', "Out_Full not asserted");
276	                check_equal(In_Level, Depth_g, "In_Level not full");
277	                check_equal(Out_Level, Depth_g, "Out_Level not full");
278	
279	                -- Add more data (not written because full)
280	                wait until falling_edge(In_Clk);
281	                In_Valid <= '1';
282	                In_Data  <= x"ABCD";
283	                wait until falling_edge(In_Clk);
284	                In_Data  <= x"8765";
285	                wait until falling_edge(In_Clk);
286	                In_Valid <= '0';
287	                wait for 1 us;
288	                check_equal(In_Full, '1', "In_Full not asserted");
289	                check_equal(Out_Full, '1', "Out_Full not asserted");
290	                check_equal(In_Level, Depth_g, "In_Level not full");
291	                check_equal(Out_Level, Depth_g, "Out_Level not full");
292	
293	                -- Check read
294	                wait until falling_edge(Out_Clk);
295	
296	                -- Read all data
297	                for i in 0 to Depth_g - 1 loop
298	                    Out_Ready <= '1';
299	                    check_equal(Out_Data, i, "Read wrong data in word " & integer'image(i));
300	                    wait until falling_edge(Out_Clk);
301	                end loop;
302	
303	                Out_Ready <= '0';
304	                wait for 1 us;
305	                check_equal(In_Empty, '1', "In_Empty not asserted");
306	                check_equal(Out_Empty, '1', "Out_Empty not asserted");
307	                check_equal(In_Full, '0', "In_Full not de-asserted");
308	                check_equal(Out_Full, '0', "Out_Full not de-asserted");
309	
310	            elsif run("ReadEmptyFifo") then
311	
312	                wait until falling_edge(Out_Clk);
313	                check_equal(Out_Empty, '1', "Out_Empty not asserted");
314	                check_equal(In_Empty, '1', "In_Empty not asserted");
315	
316	                -- read
317	                wait until falling_edge(Out_Clk);
318	                Out_Ready <= '1';
319	                wait until falling_edge(Out_Clk);
320	                Out_Ready <= '0';
321	
322	                -- check correct functionality
323	                wait for 1 us;
324	                check_equal(Out_Empty, '1', "Out_Empty not asserted");
325	                check_equal(In_Empty, '1', "In_Empty not asserted");
326	                check_equal(In_Level, 0, "In_Level not empty");
327	                check_equal(Out_Level, 0, "Out_Level not empty");
328	                wait until falling_edge(In_Clk);
329	                In_Valid  <= '1';
330	                In_Data   <= x"8765";
331	                wait until falling_edge(In_Clk);
332	                In_Valid  <= '0';
333	                wait for 1 us;
334	                check_equal(Out_Empty, '0', "Out_Empty not de-asserted");
335	                check_equal(In_Empty, '0', "In_Empty not de-asserted");
336	                check_equal(In_Level, 1, "In_Level not empty");
337	                check_equal(Out_Level, 1, "Out_Level not empty");
338	                wait until falling_edge(Out_Clk);
339	                check_equal(Out_Data, 16#8765#, "Read wrong data");
340	                Out_Ready <= '1';
341	                wait until falling_edge(Out_Clk);
342	                Out_Ready <= '0';
343	                wait for 1 us;
344	                check_equal(Out_Empty, '1', "Out_Empty not asserted");
345	                check_equal(In_Empty, '1', "In_Empty not asserted");
346	                check_equal(In_Level, 0, "In_Level not empty");
347	                check_equal(Out_Level, 0, "Out_Level not empty");
348	
349	            elsif run("AlmostFlags") then
350	
351	                -- fill
352	                for i in 0 to Depth_g - 1 loop
353	                    wait until falling_edge(In_Clk);
354	                    In_Valid <= '1';
355	                    In_Data  <= std_logic_vector(to_unsigned(i, In_Data'length));
356	                    wait until falling_edge(In_Clk);
357	                    In_Valid <= '0';
358	                    wait for 1 us;
359	                    check_equal(In_Level, i + 1, "In_Level wrong");
360	                    check_equal(Out_Level, i + 1, "Out_Level wrong");
361	                    if AlmFullOn_g then
362	                        if i + 1 >= AlmFullLevel_c then
363	                            check_equal(In_AlmFull, '1', "InAlmost Full not set");
364	                            check_equal(Out_AlmFull, '1', "OutAlmost Full not set");
365	                        else
366	                            check_equal(In_AlmFull, '0', "InAlmost Full set");
367	                            check_equal(Out_AlmFull, '0', "OutAlmost Full set");
368	                        end if;
369	                    end if;
370	                    if AlmEmptyOn_g then
371	                        if i + 1 <= AlmEmptyLevel_c then
372	                            check_equal(In_AlmEmpty, '1', "InAlmost Empty not set");
373	                            check_equal(Out_AlmEmpty, '1', "OutAlmost Empty not set");
374	                        else
375	                            check_equal(In_AlmEmpty, '0', "InAlmost Empty set");
376	                            check_equal(Out_AlmEmpty, '0', "OutAlmost Empty set");
377	                        end if;
378	                    end if;
379	                end loop;
380	
381	                -- flush
382	                for i in Depth_g - 1 downto 0 loop
383	                    wait until falling_edge(Out_Clk);
384	                    Out_Ready <= '1';
385	                    wait until falling_edge(Out_Clk);
386	                    Out_Ready <= '0';
387	                    wait for 1 us;
388	                    check_equal(In_Level, i, "In_Level wrong");
389	                    check_equal(Out_Level, i, "Out_Level wrong");
390	                    if AlmFullOn_g then
391	                        if i >= AlmFullLevel_c then
392	                            check_equal(In_AlmFull, '1', "InAlmost Full not set");
393	                            check_equal(Out_AlmFull, '1', "OutAlmost Full not set");
394	                        else
395	                            check_equal(In_AlmFull, '0', "InAlmost Full set");
396	                            check_equal(Out_AlmFull, '0', "OutAlmost Full set");
397	                        end if;
398	                    end if;
399	                    if AlmEmptyOn_g then
400	                        if i <= AlmEmptyLevel_c then
401	                            check_equal(In_AlmEmpty, '1', "InAlmost Empty not set");
402	                            check_equal(Out_AlmEmpty, '1', "OutAlmost Empty not set");
403	                        else
404	                            check_equal(In_AlmEmpty, '0', "InAlmost Empty set");
405	                            check_equal(Out_AlmEmpty, '0', "OutAlmost Empty set");
406	                        end if;
407	                    end if;
408	                end loop;
409	
410	            elsif run("DiffDutyCycle") then
411	
412	                -- Loop through all possible write duty-cycles
413	                for wrDel in 0 to 4 loop
414	
415	                    -- Loop through all possible read duty-cycles
416	                    for rdDel in 0 to 4 loop
417	                        check_equal(In_Empty, '1', "In_Empty not asserted");
418	
419	                        -- Write data
420	                        wait until falling_edge(In_Clk);
421	
422	                        -- Write 5 words
423	                        for i in 0 to 4 loop
424	                            In_Valid <= '1';
425	                            In_Data  <= std_logic_vector(to_unsigned(i, In_Data'length));
426	                            wait until falling_edge(In_Clk);
427	
428	                            -- Write delay
429	                            for k in 1 to wrDel loop
430	                                In_Valid <= '0';
431	                                In_Data  <= x"0000";
432	                                wait until falling_edge(In_Clk);
433	                            end loop;
434	
435	                        end loop;
436	
437	                        In_Valid <= '0';
438	
439	                        -- Read data
440	                        wait until falling_edge(Out_Clk);
441	
442	                        -- Read 5 words
443	                        for i in 0 to 4 loop
444	                            Out_Ready <= '1';
445	                            if Out_Valid = '0' then
446	                                wait until rising_edge(Out_Clk) and Out_Valid = '1';
447	                            end if;
448	
449	                            check_equal(Out_Data, i, "Wrong data");
450	                            wait until falling_edge(Out_Clk);
451	
452	                            -- Read delay
453	                            for k in 1 to rdDel loop
454	                                Out_Ready <= '0';
455	                                wait until falling_edge(Out_Clk);
456	                            end loop;
457	
458	                        end loop;
459	
460	                        Out_Ready <= '0';
461	                        check_equal(Out_Empty, '1', "Empty not asserted");
462	                        wait for 1 us;
463	                    end loop;
464	
465	                end loop;
466	
467	            elsif run("OutputReadyBeforeData") then
468	                Out_Ready <= '1';
469	
470	                for i in 0 to 9 loop
471	                    wait until falling_edge(Out_Clk);
472	                    wait until falling_edge(In_Clk);
473	                end loop;
474	
475	                In_Data  <= x"ABCD";
476	                In_Valid <= '1';
477	                wait until falling_edge(In_Clk);
478	                In_Data  <= x"4321";
479	                wait until falling_edge(In_Clk);
480	                In_Valid <= '0';
481	                wait until Out_Valid = '1' and rising_edge(Out_Clk);
482	                check_equal(Out_Empty, '0', "Empty asserted");
483	                check_equal(Out_Data, 16#ABCD#, "Wrong data 0");
484	                wait until Out_Valid = '1' and falling_edge(Out_Clk);
485	                check_equal(Out_Empty, '0', "Empty asserted");
486	                check_equal(Out_Data, 16#4321#, "Wrong data 1");
487	                wait until falling_edge(Out_Clk);
488	                check_equal(Out_Empty, '1', "Empty not asserted");
489	                check_equal(Out_Valid, '0', "Valid asserted");
490	            end if;
491	
492	        end loop;
493	
494	        -- TB done
495	        test_runner_cleanup(runner);
496	    end process;
497	
498	end architecture;
